module mux4to1(  
    input wire [3:0] obf_data,  
    input wire [1:0] sel,  
    output wire mux_out  
);  
    assign mux_out = (sel == 2'b00) ? obf_data[0] :  
                     (sel == 2'b01) ? obf_data[1] :  
                     (sel == 2'b10) ? obf_data[2] :  
                     obf_data[3];  
endmodule
